#!/usr/bin/env python3
"""
Corpus Builder — Scientific Word-Level Corpus (VOCAB=1017)
===========================================================
Builds the exact corpus used by all experiment scripts.

CORPUS STRUCTURE:
    base sequence = 1364 tokens (scientific text)
    default: train = base × 270 = 368280 tokens
             val   = base × 30  = 40920 tokens
             total = 300 repetitions

    The 300-rep corpus creates a gradient saturation at step ~300:
    after 300 steps × 512 tokens/step = 153600 tokens processed,
    the model has seen every bigram ~113 times and reaches the
    Adam fixed point (gradient drops suddenly).
    This is the corpus entropy floor H(corpus) ≈ 6.4 nats.

USAGE:
    python build_corpus.py              # default 300 loops → /tmp/
    python build_corpus.py --loops 60   # original 60-loop corpus
    python build_corpus.py --out /dir/  # custom output directory
    python build_corpus.py --check      # verify existing corpus

RUNS ON ANY MACHINE. No internet, no randomness.
"""
import json, argparse, os

