parser.add_argument("--out",   default="/tmp",  help="Output directory")
parser.add_argument("--loops", type=int, default=300, help="Total repetitions (default 300)")
parser.add_argument("--check", action="store_true", help="Verify existing corpus")
args = parser.parse_args()

