        with open(fname) as f:
            existing = json.load(f)
        if isinstance(existing, list) and len(existing) == len(expected):
            # Check first 100 and last 100 for speed
            sample_ok = existing[:100] == expected[:100] and existing[-100:] == expected[-100:]
            if sample_ok:
                print(f"  ✓ {label}")
            else:
                print(f"  ✗ {label} — content mismatch")
