    print(f"  val       = {BASE_LEN} × {VAL_REPS}  = {len(val_ids)} tokens")
    print(f"  Gradient saturation expected at step ~{saturation_step}")
    print(f"  (after {tokens_per_step*saturation_step//BASE_LEN} base-sequence passes)")
    print(f"  ✓ Written and verified")
